import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"天风精灵翼","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/2.C级/天风精灵翼.md","filePath":"4.资源分区/7.物品与装备/4.奇物/2.C级/天风精灵翼.md"}'),d={name:"4.资源分区/7.物品与装备/4.奇物/2.C级/天风精灵翼.md"};function p(_,a,l,i,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"天风精灵翼",tabindex:"-1"},[s("天风精灵翼 "),e("a",{class:"header-anchor",href:"#天风精灵翼","aria-label":'Permalink to "天风精灵翼"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌035")])])],-1),o('<h1 id="天风精灵翼-1" tabindex="-1">天风精灵翼 <a class="header-anchor" href="#天风精灵翼-1" aria-label="Permalink to &quot;天风精灵翼&quot;">​</a></h1><p>天风精灵翼<br> 价格：C+3000<br> 类型：奇物（披风位）<br> 描述：<br> 天风精灵翼是一件占据披风位的奇物，未激活状态下是一条披风，与一条靛青色宝石的项链，宝石的本质是高度集成化的施术单元，通过握住宝石输入不同能量来进行模式的激活与调整</p><p>【巡航模式】<br> 使用一个自由动作并消耗3点任意能量可以激活巡航模式，此时披风将会完全展开化为一主一副两对由蓝绿色粒子构成的巨大光翼。当然也可以单独输入1点能量来激活副翼。</p><p>主翼的体积最大为轮回者体积的两倍（仅画风大小，无实际效果），会令你在本场景内获得机动性为完美的飞行能力，飞行速度等同自身基础移动速度。</p><p>副翼的体积最大为轮回者体积（仅画风大小，无实际效果），会令你在本场景内的基础移动速度增加【传奇敏捷*10】+15米。</p><p>【跃迁模式】<br> 于非战斗状态下，你可以消耗1点任意能量激活跃迁模式，披风将会化为两对浮游装置，在你身前链接勾勒起传送法阵进行旅行准备，这将会花费15分钟到1小时分钟的时间，根据距离决定；在准备期间使用者不可进行其他行为，准备完成后即可完成一个传送阵以供使用，这一传送阵是单向的，仅存在一轮，只能前往你曾经去过的地方，只能在大陆内传送，这是一个C级时空来源的传送类旅行能力的效果。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',8)])])}const m=r(d,[["render",p]]);export{f as __pageData,m as default};
